import{_ as e,o as r,c as t,ae as o}from"./chunks/framework.BEtfQoF7.js";const u=JSON.parse('{"title":"법률 및 규정 준수","description":"Claude Code의 법적 계약, 규정 준수 인증 및 보안 정보입니다.","frontmatter":{"title":"법률 및 규정 준수","description":"Claude Code의 법적 계약, 규정 준수 인증 및 보안 정보입니다."},"headers":[],"relativePath":"legal-and-compliance.md","filePath":"legal-and-compliance.md","lastUpdated":1776205703000}'),l={name:"legal-and-compliance.md"};function n(h,a,i,d,c,s){return r(),t("div",null,[...a[0]||(a[0]=[o('<h1 id="법률-및-규정-준수" tabindex="-1">법률 및 규정 준수 <a class="header-anchor" href="#법률-및-규정-준수" aria-label="Permalink to &quot;법률 및 규정 준수&quot;">​</a></h1><h2 id="법적-계약" tabindex="-1">법적 계약 <a class="header-anchor" href="#법적-계약" aria-label="Permalink to &quot;법적 계약&quot;">​</a></h2><h3 id="라이선스" tabindex="-1">라이선스 <a class="header-anchor" href="#라이선스" aria-label="Permalink to &quot;라이선스&quot;">​</a></h3><p>Claude Code 사용에는 다음이 적용됩니다:</p><ul><li><a href="https://www.anthropic.com/legal/commercial-terms" target="_blank" rel="noreferrer">상업 약관</a> - Team, Enterprise 및 Claude API 사용자용</li><li><a href="https://www.anthropic.com/legal/consumer-terms" target="_blank" rel="noreferrer">소비자 서비스 약관</a> - Free, Pro 및 Max 사용자용</li></ul><h3 id="상업-계약" tabindex="-1">상업 계약 <a class="header-anchor" href="#상업-계약" aria-label="Permalink to &quot;상업 계약&quot;">​</a></h3><p>Claude API를 직접(1P) 사용하든 AWS Bedrock 또는 Google Vertex(3P)를 통해 접근하든, 상호 합의하지 않는 한 기존 상업 계약이 Claude Code 사용에 적용됩니다.</p><h2 id="규정-준수" tabindex="-1">규정 준수 <a class="header-anchor" href="#규정-준수" aria-label="Permalink to &quot;규정 준수&quot;">​</a></h2><h3 id="의료-규정-준수-baa" tabindex="-1">의료 규정 준수 (BAA) <a class="header-anchor" href="#의료-규정-준수-baa" aria-label="Permalink to &quot;의료 규정 준수 (BAA)&quot;">​</a></h3><p>고객이 당사와 사업 제휴 계약(BAA)을 체결하고 Claude Code를 사용하려는 경우, 고객이 BAA를 체결하고 <a href="/claude-code-docs-ko/zero-data-retention.html">제로 데이터 보존(ZDR)</a>을 활성화했다면 BAA가 자동으로 Claude Code에 확장 적용됩니다. BAA는 Claude Code를 통해 흐르는 해당 고객의 API 트래픽에 적용됩니다. ZDR은 조직 단위로 활성화되므로 각 조직에서 BAA의 적용을 받으려면 별도로 ZDR을 활성화해야 합니다.</p><h2 id="사용-정책" tabindex="-1">사용 정책 <a class="header-anchor" href="#사용-정책" aria-label="Permalink to &quot;사용 정책&quot;">​</a></h2><h3 id="허용되는-사용" tabindex="-1">허용되는 사용 <a class="header-anchor" href="#허용되는-사용" aria-label="Permalink to &quot;허용되는 사용&quot;">​</a></h3><p>Claude Code 사용에는 <a href="https://www.anthropic.com/legal/aup" target="_blank" rel="noreferrer">Anthropic 사용 정책</a>이 적용됩니다. Pro 및 Max 플랜의 광고된 사용 제한은 Claude Code와 Agent SDK의 일반적인 개인 사용을 전제로 합니다.</p><h3 id="인증-및-자격-증명-사용" tabindex="-1">인증 및 자격 증명 사용 <a class="header-anchor" href="#인증-및-자격-증명-사용" aria-label="Permalink to &quot;인증 및 자격 증명 사용&quot;">​</a></h3><p>Claude Code는 OAuth 토큰 또는 API 키를 사용하여 Anthropic 서버에 인증합니다. 이러한 인증 방법은 서로 다른 목적을 가집니다:</p><ul><li><strong>OAuth 인증</strong>은 Claude Free, Pro, Max, Team 및 Enterprise 구독 플랜 구매자 전용이며, Claude Code 및 기타 네이티브 Anthropic 애플리케이션의 일반적인 사용을 지원하도록 설계되었습니다. 사용자가 OAuth 토큰으로 인증하는 방법에 대한 자세한 정보는 <a href="https://support.claude.com/en/articles/13189465-logging-in-to-your-claude-account" target="_blank" rel="noreferrer">Claude 계정 로그인</a>에서 확인할 수 있습니다.</li><li>Claude의 기능과 상호 작용하는 제품이나 서비스를 구축하는 <strong>개발자</strong>(<a href="/claude-code-docs-ko/agent-sdk/overview.html">Agent SDK</a> 사용 포함)는 <a href="https://platform.claude.com/" target="_blank" rel="noreferrer">Claude Console</a> 또는 지원되는 클라우드 제공자를 통한 API 키 인증을 사용해야 합니다. Anthropic은 타사 개발자가 Claude.ai 로그인을 제공하거나 사용자를 대신하여 Free, Pro 또는 Max 플랜 자격 증명을 통해 요청을 라우팅하는 것을 허용하지 않습니다.</li></ul><p>Anthropic은 이러한 제한을 시행하기 위한 조치를 취할 권리를 보유하며, 사전 통지 없이 시행할 수 있습니다.</p><p>허용되는 인증 방법에 대한 질문은 <a href="https://www.anthropic.com/contact-sales?utm_source=claude_code&amp;utm_medium=docs&amp;utm_content=legal_compliance_contact_sales" target="_blank" rel="noreferrer">영업팀에 문의</a>하세요.</p><h2 id="보안-및-신뢰" tabindex="-1">보안 및 신뢰 <a class="header-anchor" href="#보안-및-신뢰" aria-label="Permalink to &quot;보안 및 신뢰&quot;">​</a></h2><h3 id="신뢰-및-안전" tabindex="-1">신뢰 및 안전 <a class="header-anchor" href="#신뢰-및-안전" aria-label="Permalink to &quot;신뢰 및 안전&quot;">​</a></h3><p>자세한 정보는 <a href="https://trust.anthropic.com" target="_blank" rel="noreferrer">Anthropic Trust Center</a> 및 <a href="https://www.anthropic.com/transparency" target="_blank" rel="noreferrer">Transparency Hub</a>에서 확인할 수 있습니다.</p><h3 id="보안-취약점-보고" tabindex="-1">보안 취약점 보고 <a class="header-anchor" href="#보안-취약점-보고" aria-label="Permalink to &quot;보안 취약점 보고&quot;">​</a></h3><p>Anthropic은 HackerOne을 통해 보안 프로그램을 관리합니다. <a href="https://hackerone.com/anthropic-vdp/reports/new?type=team&amp;report_type=vulnerability" target="_blank" rel="noreferrer">이 양식을 사용하여 취약점을 보고</a>하세요.</p>',23)])])}const m=e(l,[["render",n]]);export{u as __pageData,m as default};
